import { useFastSchema } from "fastschema/react";
import { useEffect, type ComponentProps, type ReactNode } from "react";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldGroup,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import {
  FastSchemaLogoIcon,
  getGlobalLinkComponent,
} from "@/components/fsui/fscommon";
import { SubmitForm, SubmitButton } from "@/components/fsui/fsform/fsform";

import { loginFormSchema, type LoginFormValues } from "./schema";

import type { User } from "fastschema";

export const LoginPage = ({
  links,
  className,
  header,
  onRendered,
  onLoginSuccess,
  onLoginError,
  ...props
}: ComponentProps<"div"> & {
  links?: {
    passwordReset?: string;
    signUp?: string;
    termsOfService?: string;
    privacyPolicy?: string;
  };
  header?: ReactNode;
  onRendered?: ({ authUser }: { authUser?: User }) => void;
  onLoginSuccess?: () => void;
  onLoginError?: (error: Error) => void;
}) => {
  const Link = getGlobalLinkComponent();
  header = header || (
    <h1 className="flex items-center self-center text-2xl">
      <Link
        href="/"
        className="flex items-center gap-2 self-center"
      >
        <span className="flex size-12 items-center justify-center">
          <FastSchemaLogoIcon />
        </span>
        <span className="font-semibold">FastSchema</span>
      </Link>
    </h1>
  );
  const { fastschema, setAuthUser } = useFastSchema();
  const authUser = fastschema.state().authUser;
  const onSubmit = async ({ value }: { value: LoginFormValues }) => {
    try {
      const res = await fastschema.auth().login("local", value);
      if (!res.token || !res.user) {
        throw new Error("Login failed");
      }

      await fastschema.sync();
      setAuthUser(res.user);
      onLoginSuccess?.();
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error("Login error:", error);
      onLoginError?.(error as Error);
    }
  };

  useEffect(() => {
    onRendered?.({ authUser });
  }, [authUser, onRendered]);

  return (
    <div className="bg-muted flex min-h-svh flex-col items-center justify-center gap-6 p-6 md:p-10">
      <div className="flex w-full max-w-sm flex-col gap-6">
        {header}
        <div
          className={cn("flex flex-col gap-6", className)}
          {...props}
        >
          <Card>
            <CardHeader className="text-center">
              <CardTitle className="text-xl">Welcome back</CardTitle>
              <CardDescription>
                Log in to your account to continue
              </CardDescription>
            </CardHeader>
            <CardContent>
              <SubmitForm<typeof loginFormSchema>
                formSchema={loginFormSchema}
                validationMethod="onChange"
                manualSubmitter={true}
                onSubmit={onSubmit}
                defaultValues={{
                  login: "",
                  password: "",
                }}
                submitter={{
                  text: "Login",
                  loadingText: "Logging in...",
                }}
                render={(form) => {
                  return (
                    <FieldGroup>
                      <form.Field
                        name="login"
                        children={(field) => {
                          const isInvalid =
                            field.state.meta.isTouched &&
                            !field.state.meta.isValid;
                          return (
                            <Field data-invalid={isInvalid}>
                              <FieldLabel htmlFor={field.name}>
                                Email
                              </FieldLabel>
                              <Input
                                id={field.name}
                                name={field.name}
                                value={field.state.value}
                                onBlur={field.handleBlur}
                                onChange={(e) =>
                                  field.handleChange(e.target.value)
                                }
                                aria-invalid={isInvalid}
                                placeholder="email@domain.ltd"
                                autoComplete="off"
                              />
                              {isInvalid && (
                                <FieldError errors={field.state.meta.errors} />
                              )}
                            </Field>
                          );
                        }}
                      />

                      <form.Field
                        name="password"
                        children={(field) => {
                          const isInvalid =
                            field.state.meta.isTouched &&
                            !field.state.meta.isValid;
                          return (
                            <Field data-invalid={isInvalid}>
                              <div className="flex items-center">
                                <FieldLabel htmlFor={field.name}>
                                  Password
                                </FieldLabel>
                                {links?.passwordReset && (
                                  <Link
                                    href="/"
                                    className="ml-auto text-sm underline-offset-4 hover:underline"
                                  >
                                    Forgot your password?
                                  </Link>
                                )}
                              </div>
                              <Input
                                id={field.name}
                                name={field.name}
                                type="password"
                                value={field.state.value}
                                onBlur={field.handleBlur}
                                onChange={(e) =>
                                  field.handleChange(e.target.value)
                                }
                                aria-invalid={isInvalid}
                                placeholder="••••••••"
                                autoComplete="off"
                              />
                              {isInvalid && (
                                <FieldError errors={field.state.meta.errors} />
                              )}
                            </Field>
                          );
                        }}
                      />

                      <form.Subscribe
                        selector={(state) => [
                          state.canSubmit,
                          state.isSubmitting,
                        ]}
                        children={([canSubmit, isSubmitting]) => (
                          <Field>
                            <SubmitButton
                              text="Login"
                              disabled={!canSubmit || isSubmitting}
                              loadingText="Logging in..."
                              isSubmitting={isSubmitting}
                            />
                            {links?.signUp && (
                              <FieldDescription className="text-center">
                                Don&apos;t have an account?{" "}
                                <Link href="/">Sign up</Link>
                              </FieldDescription>
                            )}
                          </Field>
                        )}
                      />

                      {/* <FieldSeparator className="*:data-[slot=field-separator-content]:bg-card">
                        Or continue with
                      </FieldSeparator>
                      <Field>
                        <Button
                          variant="outline"
                          type="button"
                        >
                          <svg
                            xmlns="http://www.w3.org/2000/svg"
                            viewBox="0 0 24 24"
                          >
                            <path
                              d="M12.152 6.896c-.948 0-2.415-1.078-3.96-1.04-2.04.027-3.91 1.183-4.961 3.014-2.117 3.675-.546 9.103 1.519 12.09 1.013 1.454 2.208 3.09 3.792 3.039 1.52-.065 2.09-.987 3.935-.987 1.831 0 2.35.987 3.96.948 1.637-.026 2.676-1.48 3.676-2.948 1.156-1.688 1.636-3.325 1.662-3.415-.039-.013-3.182-1.221-3.22-4.857-.026-3.04 2.48-4.494 2.597-4.559-1.429-2.09-3.623-2.324-4.39-2.376-2-.156-3.675 1.09-4.61 1.09zM15.53 3.83c.843-1.012 1.4-2.427 1.245-3.83-1.207.052-2.662.805-3.532 1.818-.78.896-1.454 2.338-1.273 3.714 1.338.104 2.715-.688 3.559-1.701"
                              fill="currentColor"
                            />
                          </svg>
                          Login with Apple
                        </Button>
                        <Button
                          variant="outline"
                          type="button"
                        >
                          <svg
                            xmlns="http://www.w3.org/2000/svg"
                            viewBox="0 0 24 24"
                          >
                            <path
                              d="M12.48 10.92v3.28h7.84c-.24 1.84-.853 3.187-1.787 4.133-1.147 1.147-2.933 2.4-6.053 2.4-4.827 0-8.6-3.893-8.6-8.72s3.773-8.72 8.6-8.72c2.6 0 4.507 1.027 5.907 2.347l2.307-2.307C18.747 1.44 16.133 0 12.48 0 5.867 0 .307 5.387.307 12s5.56 12 12.173 12c3.573 0 6.267-1.173 8.373-3.36 2.16-2.16 2.84-5.213 2.84-7.667 0-.76-.053-1.467-.173-2.053H12.48z"
                              fill="currentColor"
                            />
                          </svg>
                          Login with Google
                        </Button>
                      </Field> */}
                    </FieldGroup>
                  );
                }}
              />
              <form />
            </CardContent>
          </Card>
          {(links?.termsOfService || links?.privacyPolicy) && (
            <FieldDescription className="px-6 text-center">
              By clicking continue, you agree to our{" "}
              {links?.termsOfService && (
                <Link href={links.termsOfService}>Terms of Service</Link>
              )}
              {links?.termsOfService && links?.privacyPolicy && " and "}
              {links?.privacyPolicy && (
                <Link href={links.privacyPolicy}>Privacy Policy</Link>
              )}
              .
            </FieldDescription>
          )}
        </div>
      </div>
    </div>
  );
};

import * as z from "zod";

export const loginFormSchema = z.object({
  login: z.string().min(1, {
    message: "Email or username is required",
  }),
  password: z
    .string()
    .min(1, { message: "Password is required" })
    .min(3, { message: "Password is too short" }),
});

export type LoginFormValues = z.infer<typeof loginFormSchema>;
